#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n, ans, p[40005];
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		p[i] = i;
	}
	for (int i = 2; i <= n; i++) {
		if (p[i] == i) {
			for (int j = i; j <= n; j += i) {
                p[j] = p[j] * (i - 1) / i;
            }
		}
	}
	for (int i = 1; i < n; i++) {
		ans += p[i];
	}
	if (n == 1) {
		cout << 0;
	} else {
		cout << (ans << 1 | 1);
	}
	return 0;
}
